function burger(){let e=document.querySelector(".navbar-toggler"),i=document.querySelector(".nav"),t=document.querySelector(".contact"),s=document.querySelector(".navbar");e.addEventListener("click",function(){e.classList.contains("active"),i.classList.contains("active"),s.classList.contains("active"),t.classList.contains("active")?e.classList.remove("active")||i.classList.remove("active")||s.classList.remove("active")||t.classList.remove("active"):e.classList.add("active")||i.classList.add("active")||s.classList.add("active")||t.classList.add("active")})}burger(),new Swiper(".business__swiper > .swiper-container",{direction:"horizontal",loop:!0,freeMode:!0,spaceBetween:46,grabCursor:!1,slidesPerView:6,breakpoints:{1200:{slidesPerView:6},768:{slidesPerView:4},480:{slidesPerView:3},0:{slidesPerView:2}},autoplay:{delay:1,disableOnInteraction:!1},speed:5e3,freeModeMomentum:!1}),new Swiper(".testimonial__swiper > .swiper-container",{direction:"horizontal",loop:!0,initialSlide:0,speed:1500,slidesPerView:3.2,spaceBetween:30,autoplay:{delay:3500,disableOnInteraction:!0},breakpoints:{992:{slidesPerView:3.2},480:{slidesPerView:2},0:{slidesPerView:1}},keyboard:{enabled:!0,onlyInViewport:!1}});const scrollElements=document.querySelectorAll(".js-scroll"),elementInView=(e,i=1)=>{return e.getBoundingClientRect().top<=(window.innerHeight||document.documentElement.clientHeight)/i},elementOutofView=e=>{return e.getBoundingClientRect().top>(window.innerHeight||document.documentElement.clientHeight)},displayScrollElement=e=>{e.classList.add("scrolled")},hideScrollElement=e=>{e.classList.remove("scrolled")},handleScrollAnimation=()=>{scrollElements.forEach(e=>{elementInView(e,1.25)?displayScrollElement(e):elementOutofView(e)&&hideScrollElement(e)})};window.addEventListener("scroll",()=>{handleScrollAnimation()});